1	//! Shared consensus types and pure helper logic for the zkpow prover.
2	
3	#![no_std]
4	
5	extern crate alloc;
6	
7	use core::{
8	    mem::{align_of, size_of, MaybeUninit},
9	    ptr, slice,
10	};
11	
12	pub mod brand;
13	pub mod types;
14	
15	pub use types::{u256, BlockHash, BlockTimestamp, ChainWork, CompactTarget, Target};
16	
17	mod state;
18	pub use state::{cycle_track, cycle_track_report, State};
19	
20	mod input;
21	
22	pub use input::{
23	    parse_median_hints, parse_new_headers, serialize_median_hints, serialize_new_headers, Input,
24	    InputError, MedianTimePastHintError, NewHeaderHintError, RecursiveProof,
25	};
26	
27	/// Size of the serialized [`State`] in bytes.
28	pub const STATE_SIZE: usize = size_of::<State>();
29	
30	/// Size of a serialized [`RecursiveProof`] in bytes.
31	pub const RECURSIVE_PROOF_SIZE: usize = size_of::<RecursiveProof>();
32	
33	/// Size of each [`NewHeader`] input from the prover.
34	pub const NEW_HEADER_SIZE: usize = size_of::<NewHeader>();
35	
36	/// Size of a serialized Bitcoin block header in bytes.
37	pub const BLOCK_HEADER_SIZE: usize = size_of::<Header>();
38	
39	/// Sliding window size used for median-time-past checks.
40	pub const WINDOW_SIZE: usize = 11;
41	
42	/// Number of blocks per difficulty retarget epoch.
43	pub const EPOCH_LENGTH: u32 = 2016;
44	
45	/// Expected seconds between consecutive blocks.
46	pub const TARGET_BLOCK_TIME: u32 = 600;
47	
48	/// Expected timespan of a single difficulty epoch in seconds.
49	pub const EXPECTED_EPOCH_TIMESPAN: u32 = EPOCH_LENGTH * TARGET_BLOCK_TIME;
50	
51	/// Minimum clamped epoch timespan used for difficulty retargeting.
52	pub const MIN_EPOCH_TIMESPAN: i64 = (EXPECTED_EPOCH_TIMESPAN / 4) as i64;
53	
54	/// Maximum clamped epoch timespan used for difficulty retargeting.
55	pub const MAX_EPOCH_TIMESPAN: i64 = (EXPECTED_EPOCH_TIMESPAN * 4) as i64;
56	
57	/// Mainnet PoW limit in compact form.
58	pub const GENESIS_NBITS: u32 = 0x1d00ffff;
59	
60	/// Mainnet PoW limit as an expanded 256-bit target (the full expansion of `0x1d00ffff`).
61	///
62	/// Stored as four little-endian u64 limbs. The value is:
63	///   0x00000000FFFF0000000000000000000000000000000000000000000000000000
64	/// In LE limbs: limbs[3] = 0xFFFF0000, limbs[0..2] = 0.
65	pub const GENESIS_TARGET: Target = Target::from_limbs([0, 0, 0, 0x0000_0000_FFFF_0000]);
66	
67	/// Raw little-endian mainnet genesis block hash.
68	pub const MAINNET_GENESIS_HASH_RAW: [u8; 32] = [
69	    0x6f, 0xe2, 0x8c, 0x0a, 0xb6, 0xf1, 0xb3, 0x72, 0xc1, 0xa6, 0xa2, 0x46, 0xae, 0x63, 0xf7, 0x4f,
70	    0x93, 0x1e, 0x83, 0x65, 0xe1, 0x5a, 0x08, 0x9c, 0x68, 0xd6, 0x19, 0x00, 0x00, 0x00, 0x00, 0x00,
71	];
72	
73	#[repr(C)]
74	#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
75	pub struct Header {
76	    /// TODO: Make a newtype for Version.
77	    /// The maximally correct underlying type is a NonZero<i32>
78	    pub version: u32,
79	    pub prev_blockhash: BlockHash,
80	    pub merkle_root: [u8; 32],
81	    pub timestamp: BlockTimestamp,
82	    pub compact_target: CompactTarget,
83	    pub nonce: u32,
84	}
85	
86	impl Header {
87	    /// Serialize to exactly [`BLOCK_HEADER_SIZE`] bytes.
88	    #[must_use]
89	    pub fn to_bytes(&self) -> [u8; BLOCK_HEADER_SIZE] {
90	        copy_to_bytes(self)
91	    }
92	
93	    /// Deserialize from exactly [`BLOCK_HEADER_SIZE`] bytes.
94	    pub fn parse(bytes: &[u8]) -> Result<Self, ParseError> {
95	        cycle_track("parse/header", || copy_from_bytes(bytes))
96	    }
97	}
98	
99	/// Digest of a program verifier key.
100	#[repr(transparent)]
101	#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
102	pub struct VerifierKeyDigest([u32; 8]);
103	
104	impl VerifierKeyDigest {
105	    #[must_use]
106	    pub const fn from_raw(raw: [u32; 8]) -> Self {
107	        Self(raw)
108	    }
109	
110	    #[must_use]
111	    pub const fn as_raw(&self) -> &[u32; 8] {
112	        &self.0
113	    }
114	
115	    #[must_use]
116	    pub const fn into_raw(self) -> [u32; 8] {
117	        self.0
118	    }
119	
120	    #[must_use]
121	    pub fn to_bytes(self) -> [u8; 32] {
122	        let mut out = [0u8; 32];
123	        for (i, word) in self.0.iter().enumerate() {
124	            out[i * 4..(i + 1) * 4].copy_from_slice(&word.to_le_bytes());
125	        }
126	        out
127	    }
128	
129	    #[must_use]
130	    pub fn from_bytes(bytes: [u8; 32]) -> Self {
131	        let mut words = [0u32; 8];
132	        for (i, word) in words.iter_mut().enumerate() {
133	            *word = u32::from_le_bytes(bytes[i * 4..(i + 1) * 4].try_into().unwrap());
134	        }
135	        Self(words)
136	    }
137	}
138	
139	impl From<[u32; 8]> for VerifierKeyDigest {
140	    fn from(value: [u32; 8]) -> Self {
141	        Self(value)
142	    }
143	}
144	
145	impl From<VerifierKeyDigest> for [u32; 8] {
146	    fn from(value: VerifierKeyDigest) -> Self {
147	        value.0
148	    }
149	}
150	
151	/// Digest of committed public values.
152	#[repr(transparent)]
153	#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
154	pub struct PublicValuesDigest([u8; 32]);
155	
156	impl PublicValuesDigest {
157	    #[must_use]
158	    pub const fn from_raw(raw: [u8; 32]) -> Self {
159	        Self(raw)
160	    }
161	
162	    #[must_use]
163	    pub const fn as_raw(&self) -> &[u8; 32] {
164	        &self.0
165	    }
166	
167	    #[must_use]
168	    pub const fn into_raw(self) -> [u8; 32] {
169	        self.0
170	    }
171	}
172	
173	impl From<[u8; 32]> for PublicValuesDigest {
174	    fn from(value: [u8; 32]) -> Self {
175	        Self(value)
176	    }
177	}
178	
179	impl From<PublicValuesDigest> for [u8; 32] {
180	    fn from(value: PublicValuesDigest) -> Self {
181	        value.0
182	    }
183	}
184	
185	/// Parse errors for fixed-width serialized core types.
186	#[derive(Debug, Clone, Copy, PartialEq, Eq, thiserror::Error)]
187	pub enum ParseError {
188	    #[error("invalid length: expected {expected}, got {actual}")]
189	    InvalidLength { expected: usize, actual: usize },
190	    #[error("misaligned input requires {required}-byte alignment")]
191	    Misaligned { required: usize },
192	    #[error("truncated input at offset {offset}: need {needed} bytes, got {actual}")]
193	    Truncated {
194	        offset: usize,
195	        needed: usize,
196	        actual: usize,
197	    },
198	}
199	
200	/// Target errors that occur during arithmetic
201	#[derive(Debug, Clone, Copy, PartialEq, Eq, thiserror::Error)]
202	pub enum TargetError {
203	    #[error("invalid target: can not be max u256")]
204	    TargetTooLarge,
205	}
206	
207	pub(crate) fn check_exact_len(bytes: &[u8], expected: usize) -> Result<(), ParseError> {
208	    cycle_track("util/check_exact_len", || {
209	        if bytes.len() != expected {
210	            return Err(ParseError::InvalidLength {
211	                expected,
212	                actual: bytes.len(),
213	            });
214	        }
215	        Ok(())
216	    })
217	}
218	
219	pub(crate) fn check_aligned<T>(bytes: &[u8]) -> Result<(), ParseError> {
220	    cycle_track("util/check_aligned", || {
221	        let required = align_of::<T>();
222	        let address = bytes.as_ptr() as usize;
223	        if !address.is_multiple_of(required) {
224	            return Err(ParseError::Misaligned { required });
225	        }
226	        Ok(())
227	    })
228	}
229	
230	pub(crate) fn copy_from_bytes<T>(bytes: &[u8]) -> Result<T, ParseError> {
231	    cycle_track("util/copy_from_bytes", || {
232	        check_exact_len(bytes, size_of::<T>())?;
233	        let mut value = MaybeUninit::<T>::uninit();
234	        unsafe {
235	            ptr::copy_nonoverlapping(
236	                bytes.as_ptr(),
237	                value.as_mut_ptr() as *mut u8,
238	                size_of::<T>(),
239	            );
240	            Ok(value.assume_init())
241	        }
242	    })
243	}
244	
245	pub(crate) fn copy_to_bytes<const N: usize, T>(value: &T) -> [u8; N] {
246	    cycle_track("util/copy_to_bytes", || {
247	        assert_eq!(size_of::<T>(), N);
248	        let mut bytes = [0u8; N];
249	        unsafe {
250	            ptr::copy_nonoverlapping(value as *const T as *const u8, bytes.as_mut_ptr(), N);
251	        }
252	        bytes
253	    })
254	}
255	
256	pub(crate) fn ref_from_bytes<T>(bytes: &[u8]) -> Result<&T, ParseError> {
257	    cycle_track("util/ref_from_bytes", || {
258	        check_exact_len(bytes, size_of::<T>())?;
259	        check_aligned::<T>(bytes)?;
260	        Ok(unsafe { &*(bytes.as_ptr() as *const T) })
261	    })
262	}
263	
264	pub(crate) fn slice_from_bytes<T>(bytes: &[u8]) -> Result<&[T], ParseError> {
265	    cycle_track("util/slice_from_bytes", || {
266	        if !bytes.len().is_multiple_of(size_of::<T>()) {
267	            return Err(ParseError::InvalidLength {
268	                expected: bytes.len().div_ceil(size_of::<T>()) * size_of::<T>(),
269	                actual: bytes.len(),
270	            });
271	        }
272	        check_aligned::<T>(bytes)?;
273	        Ok(unsafe {
274	            slice::from_raw_parts(bytes.as_ptr() as *const T, bytes.len() / size_of::<T>())
275	        })
276	    })
277	}
278	
279	/// Prover-supplied fields for a new header.
280	#[repr(C)]
281	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
282	pub struct NewHeader {
283	    pub version: u32,
284	    pub merkle_root: [u8; 32],
285	    pub timestamp: BlockTimestamp,
286	    pub nonce: u32,
287	}
288	
289	impl NewHeader {
290	    /// Extract the prover-supplied subset of fields from a full [`Header`].
291	    #[must_use]
292	    pub fn from_header(header: &Header) -> Self {
293	        Self {
294	            version: header.version,
295	            merkle_root: header.merkle_root,
296	            timestamp: header.timestamp,
297	            nonce: header.nonce,
298	        }
299	    }
300	
301	    /// Parse a [`NewHeader`] from the flat input buffer at `offset`.
302	    pub fn parse_at(data: &[u8], offset: usize) -> Result<Self, ParseError> {
303	        let end = offset
304	            .checked_add(NEW_HEADER_SIZE)
305	            .ok_or(ParseError::Truncated {
306	                offset,
307	                needed: NEW_HEADER_SIZE,
308	                actual: data.len().saturating_sub(offset),
309	            })?;
310	        let bytes = data.get(offset..end).ok_or(ParseError::Truncated {
311	            offset,
312	            needed: NEW_HEADER_SIZE,
313	            actual: data.len().saturating_sub(offset),
314	        })?;
315	        Self::parse(bytes)
316	    }
317	
318	    /// Parse a [`NewHeader`] from exactly [`NEW_HEADER_SIZE`] bytes.
319	    pub fn parse(bytes: &[u8]) -> Result<Self, ParseError> {
320	        cycle_track("parse/new_header", || copy_from_bytes(bytes))
321	    }
322	
323	    /// Borrow a slice of [`NewHeader`] records directly from aligned protocol bytes.
324	    pub fn slice_from_bytes(bytes: &[u8]) -> Result<&[Self], ParseError> {
325	        cycle_track("parse/new_header_slice", || slice_from_bytes(bytes))
326	    }
327	
328	    /// Serialize to exactly [`NEW_HEADER_SIZE`] bytes.
329	    #[must_use]
330	    pub fn to_bytes(&self) -> [u8; NEW_HEADER_SIZE] {
331	        copy_to_bytes(self)
332	    }
333	
334	    /// Materialize a full [`Header`] using authenticated chain context.
335	    #[must_use]
336	    pub fn into_header(self, prev_blockhash: BlockHash, compact_target: CompactTarget) -> Header {
337	        Header {
338	            version: self.version,
339	            prev_blockhash,
340	            merkle_root: self.merkle_root,
341	            timestamp: self.timestamp,
342	            compact_target,
343	            nonce: self.nonce,
344	        }
345	    }
346	}
347	
348	// ============================================================================
349	// Public claim and private continuation types (Step 3)
350	// ============================================================================
351	
352	/// The verifier-visible portion of a validated chain segment.
353	#[repr(C)]
354	#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
355	pub struct PublicChainClaim {
356	    pub genesis_hash: BlockHash,
357	    pub tip_hash: BlockHash,
358	    pub chain_work: ChainWork,
359	    pub height: u32,
360	}
361	
362	/// Size of a serialized [`PublicChainClaim`] in bytes.
363	pub const PUBLIC_CHAIN_CLAIM_SIZE: usize = 32 + 32 + 32 + 4;
364	
365	impl PublicChainClaim {
366	    #[must_use]
367	    pub fn to_bytes(&self) -> [u8; PUBLIC_CHAIN_CLAIM_SIZE] {
368	        let mut out = [0u8; PUBLIC_CHAIN_CLAIM_SIZE];
369	        out[0..32].copy_from_slice(self.genesis_hash.to_le_bytes_slice());
370	        out[32..64].copy_from_slice(self.tip_hash.to_le_bytes_slice());
371	        out[64..96].copy_from_slice(self.chain_work.to_le_bytes_slice());
372	        out[96..100].copy_from_slice(&self.height.to_le_bytes());
373	        out
374	    }
375	
376	    pub fn parse(bytes: &[u8]) -> Result<Self, ParseError> {
377	        check_exact_len(bytes, PUBLIC_CHAIN_CLAIM_SIZE)?;
378	        let genesis_hash = BlockHash::new(bytes[0..32].try_into().unwrap());
379	        let tip_hash = BlockHash::new(bytes[32..64].try_into().unwrap());
380	        let chain_work = ChainWork::from_le_bytes(bytes[64..96].try_into().unwrap());
381	        let height = u32::from_le_bytes(bytes[96..100].try_into().unwrap());
382	        Ok(Self {
383	            genesis_hash,
384	            tip_hash,
385	            chain_work,
386	            height,
387	        })
388	    }
389	}
390	
391	/// The private continuation state carried between recursive proof iterations.
392	///
393	/// This is committed only as a digest in the public values; the raw bytes are
394	/// supplied as a private witness when extending a proof.
395	///
396	/// Serialized without struct padding (116 bytes):
397	/// ```text
398	///  0..  4  current_nbits           u32 LE
399	///  4.. 36  current_work            [u64; 4] LE
400	/// 36.. 68  current_target          [u64; 4] LE
401	/// 68.. 72  epoch_start_timestamp   u32 LE
402	/// 72..116  timestamps              [u32; 11] LE
403	/// ```
404	#[repr(C)]
405	#[derive(Debug, Clone, PartialEq, Eq)]
406	pub struct PrivateContinuationState {
407	    pub current_nbits: CompactTarget,
408	    pub current_work: ChainWork,
409	    pub current_target: Target,
410	    pub epoch_start_timestamp: BlockTimestamp,
411	    pub timestamps: [BlockTimestamp; WINDOW_SIZE],
412	}
413	
414	/// Size of the serialized [`PrivateContinuationState`] in bytes (no padding).
415	pub const PRIVATE_CONTINUATION_STATE_SIZE: usize = 4 + 32 + 32 + 4 + 4 * WINDOW_SIZE;
416	
417	impl PrivateContinuationState {
418	    #[must_use]
419	    pub fn from_state(state: &State) -> Self {
420	        Self {
421	            current_nbits: state.current_nbits,
422	            current_work: state.current_work,
423	            current_target: state.current_target,
424	            epoch_start_timestamp: state.epoch_start_timestamp,
425	            timestamps: state.timestamps,
426	        }
427	    }
428	
429	    #[must_use]
430	    pub fn to_bytes(&self) -> [u8; PRIVATE_CONTINUATION_STATE_SIZE] {
431	        let mut out = [0u8; PRIVATE_CONTINUATION_STATE_SIZE];
432	        out[0..4].copy_from_slice(self.current_nbits.to_le_bytes_slice());
433	        out[4..36].copy_from_slice(self.current_work.to_le_bytes_slice());
434	        out[36..68].copy_from_slice(self.current_target.to_le_bytes_slice());
435	        out[68..72].copy_from_slice(self.epoch_start_timestamp.to_le_bytes_slice());
436	        for (i, ts) in self.timestamps.iter().enumerate() {
437	            out[72 + i * 4..72 + (i + 1) * 4].copy_from_slice(ts.to_le_bytes_slice());
438	        }
439	        out
440	    }
441	
442	    pub fn parse(bytes: &[u8]) -> Result<Self, ParseError> {
443	        check_exact_len(bytes, PRIVATE_CONTINUATION_STATE_SIZE)?;
444	        let current_nbits = CompactTarget::new(u32::from_le_bytes(bytes[0..4].try_into().unwrap()));
445	        let current_work = ChainWork::from_le_bytes(bytes[4..36].try_into().unwrap());
446	        let current_target = Target::from_le_bytes(bytes[36..68].try_into().unwrap());
447	        let epoch_start_timestamp =
448	            BlockTimestamp::from_le_bytes(bytes[68..72].try_into().unwrap());
449	        let mut timestamps = [BlockTimestamp::default(); WINDOW_SIZE];
450	        for (i, ts) in timestamps.iter_mut().enumerate() {
451	            *ts = BlockTimestamp::from_le_bytes(
452	                bytes[72 + i * 4..72 + (i + 1) * 4].try_into().unwrap(),
453	            );
454	        }
455	        Ok(Self {
456	            current_nbits,
457	            current_work,
458	            current_target,
459	            epoch_start_timestamp,
460	            timestamps,
461	        })
462	    }
463	}
464	
465	// ValidationState has been removed as it was only used in tests.
466	
467	/// Validation status emitted by the program on failure.
468	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
469	#[repr(u8)]
470	pub enum ValidationErrorCode {
471	    HeaderPayloadLengthInvalid = 1,
472	    PowInsufficient = 2,
473	    TimestampTooOld = 3,
474	    GenesisHashMismatch = 4,
475	}
476	
477	impl ValidationErrorCode {
478	    /// Return the committed byte representation for the error code.
479	    #[must_use]
480	    pub const fn as_byte(self) -> u8 {
481	        self as u8
482	    }
483	
484	    /// Return a human-readable description for the code.
485	    #[must_use]
486	    pub const fn description(self) -> &'static str {
487	        match self {
488	            Self::HeaderPayloadLengthInvalid => "Header payload length invalid",
