537	/// Wire layout of the minimal public values committed by the prover.
538	///
539	/// Layout (169 bytes, little-endian):
540	/// ```text
541	///  0.. 32  genesis_hash        [u8; 32]
542	/// 32.. 64  tip_hash            [u8; 32]
543	/// 64.. 96  chain_work          [u8; 32]  (u256 LE)
544	/// 96..100  height              u32 LE
545	/// 100      return_code         u8  (0 = success, nonzero = failure)
546	/// 101..105 failure_height      u32 LE  (0 on success)
547	/// 105..137 continuation_digest [u8; 32]
548	/// 137..169 verifier_key         [u8; 32]  ([u32; 8] LE words)
549	/// ```
550	///
551	/// Serialized manually to avoid struct padding; use [`MinimalPublicValues::to_bytes`]
552	/// and [`MinimalPublicValues::parse`] rather than transmuting.
553	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
554	pub struct MinimalPublicValues {
555	    pub genesis_hash: BlockHash,
556	    pub tip_hash: BlockHash,
557	    pub chain_work: [u8; 32],
558	    pub height: u32,
559	    pub return_code: u8,
560	    pub failure_height: u32,
561	    pub continuation_digest: [u8; 32],
562	    pub verifier_key: VerifierKeyDigest,
563	}
564	
565	/// Size of the serialized [`MinimalPublicValues`] in bytes.
566	pub const MINIMAL_PV_SIZE: usize = 32 + 32 + 32 + 4 + 1 + 4 + 32 + 32; // = 169
