609	    /// Serialize to exactly [`MINIMAL_PV_SIZE`] bytes (no padding).
610	    #[must_use]
611	    pub fn to_bytes(&self) -> [u8; MINIMAL_PV_SIZE] {
612	        let mut out = [0u8; MINIMAL_PV_SIZE];
613	        out[0..32].copy_from_slice(self.genesis_hash.to_le_bytes_slice());
614	        out[32..64].copy_from_slice(self.tip_hash.to_le_bytes_slice());
615	        out[64..96].copy_from_slice(&self.chain_work);
616	        out[96..100].copy_from_slice(&self.height.to_le_bytes());
617	        out[100] = self.return_code;
618	        out[101..105].copy_from_slice(&self.failure_height.to_le_bytes());
619	        out[105..137].copy_from_slice(&self.continuation_digest);
620	        out[137..169].copy_from_slice(&self.verifier_key.to_bytes());
621	        out
622	    }
