624	    /// Deserialize from exactly [`MINIMAL_PV_SIZE`] bytes.
625	    pub fn parse(bytes: &[u8]) -> Result<Self, PublicValuesParseError> {
626	        if bytes.len() != MINIMAL_PV_SIZE {
627	            return Err(PublicValuesParseError::InvalidLength {
628	                actual: bytes.len(),
629	            });
630	        }
631	        let genesis_hash = BlockHash::new(bytes[0..32].try_into().unwrap());
632	        let tip_hash = BlockHash::new(bytes[32..64].try_into().unwrap());
633	        let chain_work: [u8; 32] = bytes[64..96].try_into().unwrap();
634	        let height = u32::from_le_bytes(bytes[96..100].try_into().unwrap());
635	        let return_code = bytes[100];
636	        let failure_height = u32::from_le_bytes(bytes[101..105].try_into().unwrap());
637	        let continuation_digest: [u8; 32] = bytes[105..137].try_into().unwrap();
638	        let verifier_key = VerifierKeyDigest::from_bytes(bytes[137..169].try_into().unwrap());
639	        Ok(Self {
640	            genesis_hash,
641	            tip_hash,
642	            chain_work,
643	            height,
644	            return_code,
645	            failure_height,
646	            continuation_digest,
647	            verifier_key,
648	        })
649	    }
