774	/// Convert a full 256-bit target into compact `bits` encoding.
775	#[must_use]
776	pub fn target_to_bits(target: Target) -> CompactTarget {
777	    cycle_track("difficulty/target_to_bits", || {
778	        let bytes = target.to_le_bytes();
779	        let mut nbytes = 32usize;
780	        while nbytes > 0 && bytes[nbytes - 1] == 0 {
781	            nbytes -= 1;
782	        }
783	        if nbytes == 0 {
784	            return CompactTarget::new(0);
785	        }
786	
787	        let mut compact = if nbytes <= 3 {
788	            let mut value = 0u32;
789	            for i in (0..nbytes).rev() {
790	                value = (value << 8) | bytes[i] as u32;
791	            }
792	            value << (8 * (3 - nbytes))
793	        } else {
794	            ((bytes[nbytes - 1] as u32) << 16)
795	                | ((bytes[nbytes - 2] as u32) << 8)
796	                | (bytes[nbytes - 3] as u32)
797	        };
798	
799	        if (compact & 0x0080_0000) != 0 {
800	            compact >>= 8;
801	            nbytes += 1;
802	        }
803	
804	        CompactTarget::new(((nbytes as u32) << 24) | (compact & 0x007f_ffff))
805	    })
806	}
807	
808	/// Expand compact Bitcoin `bits` into a normalized full 256-bit target.
809	#[must_use]
810	pub fn target_from_bits(compact_target: CompactTarget) -> Target {
811	    cycle_track("difficulty/target_from_bits", || {
812	        let bits = compact_target.into_inner();
813	        let size = (bits >> 24) as usize;
814	        let mantissa = bits & 0x007f_ffff;
815	        let mut normalized_target_bytes = [0u8; 32];
816	
817	        if size <= 3 {
818	            let value = mantissa >> (8 * (3 - size));
819	            normalized_target_bytes[0..4].copy_from_slice(&value.to_le_bytes());
820	        } else {
821	            let offset = size - 3;
822	            if offset < 32 {
823	                normalized_target_bytes[offset] = (mantissa & 0xff) as u8;
824	            }
825	            if offset + 1 < 32 {
826	                normalized_target_bytes[offset + 1] = ((mantissa >> 8) & 0xff) as u8;
827	            }
828	            if offset + 2 < 32 {
829	                normalized_target_bytes[offset + 2] = ((mantissa >> 16) & 0xff) as u8;
830	            }
831	        }
832	
833	        Target::from_le_bytes(normalized_target_bytes)
834	    })
835	}
