885	/// Subtract `rhs` from `self` in place. Returns `true` if there was an underflow (borrow out).
886	#[must_use]
887	fn sub_assign(lhs: &mut u256, rhs: u256) -> bool {
888	    let mut borrow = false;
889	
890	    let lhs_limbs: &mut [u64; 4] = lhs.as_limbs_mut();
891	    let rhs_limbs = rhs.as_limbs();
892	
893	    let (a, b1) = lhs_limbs[0].overflowing_sub(rhs_limbs[0]);
894	    let (a, b2) = a.overflowing_sub(borrow as u64);
895	    lhs_limbs[0] = a;
896	    borrow = b1 || b2;
897	
898	    let (a, b1) = lhs_limbs[1].overflowing_sub(rhs_limbs[1]);
899	    let (a, b2) = a.overflowing_sub(borrow as u64);
900	    lhs_limbs[1] = a;
901	    borrow = b1 || b2;
902	
903	    let (a, b1) = lhs_limbs[2].overflowing_sub(rhs_limbs[2]);
904	    let (a, b2) = a.overflowing_sub(borrow as u64);
905	    lhs_limbs[2] = a;
906	    borrow = b1 || b2;
907	
908	    let (a, b1) = lhs_limbs[3].overflowing_sub(rhs_limbs[3]);
909	    let (a, b2) = a.overflowing_sub(borrow as u64);
910	    lhs_limbs[3] = a;
911	    borrow = b1 || b2;
912	
913	    borrow
914	}
