916	/// Add one to a target, modifying the limbs in place.
917	///
918	/// A valid target can not be a max u256, so:
919	///   - It can't carry over into a 5th limb
920	///   - A carry can only start if the first limb is max u64
921	///   - A carry can only continue if the next limb is a max u64
922	///   - A max u64 with a carry-over of 1 becomes 0
923	///
924	/// We can iterate until we find a limb < max u64, add 1 to it, and we're done. As long as we find max u64 limbs we
925	/// just set them to 0 and move forward. Iterating fully without hitting a non-max u64 indicates that we have bad
926	/// data; the target is invalid and we return an error.
927	fn increment_target(target: &mut u256) -> Result<(), TargetError> {
928	    cycle_track("pow/work/target_plus_one", || {
929	        for (i, limb) in target.as_limbs_mut().iter_mut().enumerate() {
930	            // This limb isn't saturated so it can't carry; add 1 and we're done.
931	            if *limb < u64::MAX {
932	                *limb += 1;
933	                break;
934	            }
935	
936	            // If we're here at the last index then all limbs are saturated and the target is invalid.
937	            if i == 3 {
938	                return Err(TargetError::TargetTooLarge);
939	            }
940	
941	            // This limb is saturated but not the final limb, so roll it over to 0 and proceed with the carry
942	            *limb = 0;
943	        }
944	        Ok(())
945	    })
946	}
947	
948	/// Shift `value` left by one bit in place, returning the carry (the evicted MSB).
949	#[must_use]
950	fn shl1_with_carry(value: &mut u256) -> bool {
951	    cycle_track("pow/work/shl1_with_carry", || {
952	        let limbs = value.as_limbs_mut();
953	        let mut carry = 0u64;
954	        for limb in limbs.iter_mut() {
955	            let next_carry = *limb >> 63;
956	            *limb = (*limb << 1) | carry;
957	            carry = next_carry;
958	        }
959	        carry > 0
960	    })
961	}
962	
963	/// Compute one-block cumulative-work units from the expanded target.
964	///
965	/// Uses non-restoring binary long division to compute `floor(2^256 / (target + 1))`.
966	/// The loop processes 257 bits (indices 256 down to 0): at `bit == 256` we introduce
967	/// the implicit leading 1 of the dividend `2^256`; for `bit < 256` we set the
968	/// corresponding quotient bit when the remainder meets the divisor.
969	pub fn work_from_target(target: Target) -> Result<ChainWork, TargetError> {
970	    cycle_track("pow/work_from_target", || {
971	        let mut divisor = *target.as_inner();
972	        increment_target(&mut divisor)?;
973	
974	        let mut remainder = u256::from_limbs([0u64; 4]);
975	        let mut quotient = [0u64; 4];
976	        for bit in (0..=256u32).rev() {
977	            // Shift remainder left, absorbing the next dividend bit.
978	            // At bit == 256 the dividend is 2^256, so its MSB is 1; all lower bits are 0.
979	            let carry = shl1_with_carry(&mut remainder);
980	            if bit == 256 {
981	                // Inject the implicit leading 1 of 2^256 into the LSB of the shifted remainder.
982	                remainder.as_limbs_mut()[0] |= 1;
983	            }
984	            // If carry is set the remainder is effectively > 2^256, which is always >= divisor.
985	
986	            if carry || remainder >= divisor {
987	                let _ = sub_assign(&mut remainder, divisor);
988	                if bit < 256 {
989	                    quotient[(bit / 64) as usize] |= 1u64 << (bit % 64);
990	                }
991	            }
992	        }
993	
994	        Ok(ChainWork::from_limbs(quotient))
995	    })
996	}
