998	/// Compute the compact and normalized full target required at a difficulty boundary.
999	#[must_use]
1000	pub fn calculate_next_target_required(
1001	    old_target: Target,
1002	    epoch_start_timestamp: BlockTimestamp,
1003	    previous_timestamp: BlockTimestamp,
1004	) -> (CompactTarget, Target) {
1005	    cycle_track("pow/calculate_next_target_required", || {
1006	        // Normalize the timespan to ensure it's within the min/max bounds allowed.
1007	        let actual_timespan = i64::from(*previous_timestamp) - i64::from(*epoch_start_timestamp);
1008	        let clamped_timespan = actual_timespan.clamp(MIN_EPOCH_TIMESPAN, MAX_EPOCH_TIMESPAN) as u32;
1009	
1010	        // Calculate the raw target value from the normalized previous target and the timespan.
1011	        let mut target_limbs = old_target.into_inner().into_limbs();
1012	        let mut carry = 0u128;
1013	        for limb in &mut target_limbs {
1014	            let product = (*limb as u128) * (clamped_timespan as u128) + carry;
1015	            *limb = product as u64;
1016	            carry = product >> 64;
1017	        }
1018	
1019	        let mut remainder = 0u128;
1020	        for limb in target_limbs.iter_mut().rev() {
1021	            let value = (remainder << 64) | (*limb as u128);
1022	            *limb = (value / (EXPECTED_EPOCH_TIMESPAN as u128)) as u64;
1023	            remainder = value % (EXPECTED_EPOCH_TIMESPAN as u128);
1024	        }
1025	
1026	        // Normalize the new target to ensure an upper-bound (a minimum difficulty) and to handle the implicit
1027	        // truncation that occurs when round-tripping through the nbits format.
1028	        let calculated_target = Target::from_limbs(target_limbs);
1029	        let clamped_target = calculated_target.min(GENESIS_TARGET);
1030	        let compact_target = target_to_bits(clamped_target);
1031	        let normalized_target = target_from_bits(compact_target);
1032	
1033	        // The target is capped above and truncated below; return it and the compact form we calculated along the way.
1034	        (compact_target, normalized_target)
1035	    })
1036	}
