1096	    fn median_hints_for_headers(
1097	        initial_state: &State,
1098	        headers: &[NewHeader],
1099	    ) -> Vec<BlockTimestamp> {
1100	        let mut state = initial_state.clone();
1101	        let mut medians = Vec::with_capacity(headers.len());
1102	        for header in headers {
1103	            medians.push(median_time_past(&state));
1104	            let timestamp_slot = (state.height as usize + 1) % WINDOW_SIZE;
1105	            state.timestamps[timestamp_slot] = header.timestamp;
1106	            state.height += 1;
1107	        }
1108	        medians
1109	    }
