1650	            timestamps: [BlockTimestamp::new(10); WINDOW_SIZE],
1651	        };
1652	        let bytes = pcs.to_bytes();
1653	        assert_eq!(bytes.len(), PRIVATE_CONTINUATION_STATE_SIZE);
1654	        let parsed = PrivateContinuationState::parse(&bytes).unwrap();
1655	        assert_eq!(parsed, pcs);
