1658	    #[test]
1659	    fn state_continuation_bytes_matches_pcs_to_bytes() {
1660	        let state = State {
1661	            current_nbits: CompactTarget::new(GENESIS_NBITS),
1662	            current_work: ChainWork::from_limbs([1, 2, 3, 4]),
