30	    let b7 = state[7].to_be_bytes();
31	    [
32	        b0[4], b0[5], b0[6], b0[7], //
33	        b1[4], b1[5], b1[6], b1[7], //
34	        b2[4], b2[5], b2[6], b2[7], //
35	        b3[4], b3[5], b3[6], b3[7], //
36	        b4[4], b4[5], b4[6], b4[7], //
