53	/// - Block 2: bytes 64–79 (16 data bytes) + 0x80 + 47 zeros + 8-byte length (640 bits)
54	pub(crate) fn sha256_80bytes(data: &[u8; 80]) -> [u8; 32] {
55	    let mut state = SHA256_IV;
56	
57	    // ── Block 1: bytes 0–63 ──
58	    let mut w = [0u64; 64];
59	    w[0] = be_u64(data[0], data[1], data[2], data[3]);
60	    w[1] = be_u64(data[4], data[5], data[6], data[7]);
61	    w[2] = be_u64(data[8], data[9], data[10], data[11]);
62	    w[3] = be_u64(data[12], data[13], data[14], data[15]);
63	    w[4] = be_u64(data[16], data[17], data[18], data[19]);
64	    w[5] = be_u64(data[20], data[21], data[22], data[23]);
65	    w[6] = be_u64(data[24], data[25], data[26], data[27]);
66	    w[7] = be_u64(data[28], data[29], data[30], data[31]);
67	    w[8] = be_u64(data[32], data[33], data[34], data[35]);
68	    w[9] = be_u64(data[36], data[37], data[38], data[39]);
69	    w[10] = be_u64(data[40], data[41], data[42], data[43]);
70	    w[11] = be_u64(data[44], data[45], data[46], data[47]);
71	    w[12] = be_u64(data[48], data[49], data[50], data[51]);
72	    w[13] = be_u64(data[52], data[53], data[54], data[55]);
73	    w[14] = be_u64(data[56], data[57], data[58], data[59]);
74	    w[15] = be_u64(data[60], data[61], data[62], data[63]);
75	    syscall_sha256_extend(&mut w);
76	    syscall_sha256_compress(&mut w, &mut state);
77	
78	    // ── Block 2: bytes 64–79 + padding + length ──
79	    // Layout: [data 16 bytes | 0x80 | 47× 0x00 | 8-byte big-endian length 640 = 0x280]
80	    let mut w = [0u64; 64];
81	    w[0] = be_u64(data[64], data[65], data[66], data[67]);
82	    w[1] = be_u64(data[68], data[69], data[70], data[71]);
83	    w[2] = be_u64(data[72], data[73], data[74], data[75]);
84	    w[3] = be_u64(data[76], data[77], data[78], data[79]);
85	    // 0x80 byte at word index 4, byte 0 → 0x80000000
86	    w[4] = 0x80000000;
87	    // w[15] = lower 32 bits of length = 640 = 0x280
88	    w[15] = 0x280;
89	
90	    syscall_sha256_extend(&mut w);
91	    syscall_sha256_compress(&mut w, &mut state);
