11	// ============================================================================
12	// Input & InputError
13	// ============================================================================
14	
15	/// Complete typed public prover input.
16	///
17	/// The full validation state is supplied separately as private witness data.
18	/// Its public preimage fields must match [`claim`](Self::claim) before the
19	/// guest uses it to validate headers.
20	#[derive(Debug, Clone, PartialEq, Eq)]
21	pub struct Input {
22	    pub claim: PublicChainClaim,
