26	/// Recursive proof metadata that authenticates the current [`State`](crate::State).
27	///
28	/// `previous_return_code` must be 0 (success) for the guest to accept the
29	/// recursive continuation.  A nonzero value means the prior proof committed a
30	/// validation failure, and extending from it is rejected.
31	#[repr(C)]
32	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
33	pub struct RecursiveProof {
34	    pub verifier_key: VerifierKeyDigest,
35	    pub public_values_digest: PublicValuesDigest,
36	    /// Return code from the previous proof (0 = success, nonzero = failure).
37	    pub previous_return_code: u8,
38	    /// Padding to maintain 4-byte alignment.
39	    pub _pad: [u8; 3],
40	}
