45	            verifier_key: VerifierKeyDigest::from_raw([0u32; 8]),
46	            public_values_digest: PublicValuesDigest::from_raw([0u8; 32]),
47	            previous_return_code: 0,
48	            _pad: [0u8; 3],
49	        }
50	    }
51	}
