53	/// Parse and validation errors for [`Input`].
54	#[derive(Debug, Clone, Copy, PartialEq, Eq, thiserror::Error)]
55	pub enum InputError {
56	    #[error("input parse error: {0}")]
57	    Parse(ParseError),
58	}
59	
60	/// Parse and validation errors for the new-header private witness batch.
61	#[derive(Debug, Clone, Copy, PartialEq, Eq, thiserror::Error)]
62	pub enum NewHeaderHintError {
63	    #[error("new-header hint payload length mismatch: expected {expected} bytes, got {actual}")]
64	    PayloadLengthInvalid { expected: usize, actual: usize },
65	    #[error("new-header hint parse error: {0}")]
66	    Parse(ParseError),
67	}
