84	impl RecursiveProof {
85	    /// Parse and validate a RecursiveProof from exactly [`RECURSIVE_PROOF_SIZE`] bytes.
86	    pub fn parse(bytes: &[u8]) -> Result<Self, InputError> {
87	        cycle_track("input/recursive_proof", || {
88	            copy_from_bytes(bytes).map_err(InputError::from)
89	        })
90	    }
91	
92	    /// Serialize to exactly [`RECURSIVE_PROOF_SIZE`] bytes.
93	    #[must_use]
94	    pub fn to_bytes(&self) -> [u8; RECURSIVE_PROOF_SIZE] {
95	        copy_to_bytes(self)
96	    }
97	}
98	
99	/// Serialize new headers.
100	#[must_use]
101	pub fn serialize_new_headers(headers: &[NewHeader]) -> Vec<u8> {
102	    let mut bytes = Vec::with_capacity(headers.len() * NEW_HEADER_SIZE);
103	    for header in headers {
104	        bytes.extend_from_slice(&header.to_bytes());
105	    }
106	    bytes
107	}
108	
109	/// Parse new headers as a zero-copy slice reference.
110	pub fn parse_new_headers(bytes: &[u8]) -> Result<&[NewHeader], NewHeaderHintError> {
111	    cycle_track("input/parse/new_header_hints", || {
112	        if !bytes.len().is_multiple_of(NEW_HEADER_SIZE) {
113	            return Err(NewHeaderHintError::PayloadLengthInvalid {
114	                expected: bytes.len().div_ceil(NEW_HEADER_SIZE) * NEW_HEADER_SIZE,
115	                actual: bytes.len(),
116	            });
117	        }
118	
119	        let headers = slice_from_bytes::<NewHeader>(bytes).map_err(NewHeaderHintError::Parse)?;
120	        Ok(headers)
121	    })
122	}
123	
124	/// Serialize median hints.
125	#[must_use]
126	pub fn serialize_median_hints(medians: &[BlockTimestamp]) -> Vec<u8> {
127	    let mut bytes = Vec::with_capacity(medians.len() * 4);
128	    for median in medians {
129	        bytes.extend_from_slice(&median.to_le_bytes());
130	    }
131	    bytes
132	}
133	
134	/// Parse median hints as a zero-copy slice reference.
135	pub fn parse_median_hints(
136	    bytes: &[u8],
137	    expected_count: usize,
138	) -> Result<&[BlockTimestamp], MedianTimePastHintError> {
139	    cycle_track("input/parse/median_time_past_hints", || {
140	        let expected_len = expected_count * core::mem::size_of::<BlockTimestamp>();
141	        if bytes.len() != expected_len {
142	            return Err(MedianTimePastHintError::PayloadLengthInvalid {
143	                expected: expected_len,
144	                actual: bytes.len(),
145	            });
146	        }
147	
148	        let medians =
149	            slice_from_bytes::<BlockTimestamp>(bytes).map_err(MedianTimePastHintError::Parse)?;
150	        Ok(medians)
151	    })
152	}
153	
154	/// Split and validate the wire layout, returning `(claim_bytes, proof_bytes)`.
155	///
156	/// `Input` intentionally carries only the public claim and recursive proof
157	/// metadata. The full [`State`](crate::State) is supplied separately as private
158	/// witness data and checked against this claim before use.
159	fn split_input_wire(bytes: &[u8]) -> Result<(&[u8], &[u8]), InputError> {
160	    check_exact_len(bytes, PUBLIC_CHAIN_CLAIM_SIZE + RECURSIVE_PROOF_SIZE)?;
161	    Ok((
162	        &bytes[..PUBLIC_CHAIN_CLAIM_SIZE],
163	        &bytes[PUBLIC_CHAIN_CLAIM_SIZE..],
164	    ))
165	}
166	
167	impl Input {
168	    /// Constructs a new Input.
169	    pub fn new(claim: PublicChainClaim, recursive_proof: RecursiveProof) -> Self {
170	        Self {
171	            claim,
172	            recursive_proof,
173	        }
174	    }
175	
176	    /// Parse and validate input from the host/guest wire format.
177	    pub fn parse(bytes: &[u8]) -> Result<Self, InputError> {
178	        cycle_track("input/parse", || {
179	            let (claim_bytes, proof_bytes) = split_input_wire(bytes)?;
180	            let claim = cycle_track("input/parse/claim", || {
181	                PublicChainClaim::parse(claim_bytes).map_err(InputError::from)
182	            })?;
183	            let recursive_proof = RecursiveProof::parse(proof_bytes)?;
184	            Ok(Self {
185	                claim,
186	                recursive_proof,
187	            })
188	        })
189	    }
190	
191	    /// Serialize to the host/guest wire format.
192	    #[must_use]
193	    pub fn to_bytes(&self) -> Vec<u8> {
194	        let mut bytes = Vec::with_capacity(PUBLIC_CHAIN_CLAIM_SIZE + RECURSIVE_PROOF_SIZE);
195	        bytes.extend_from_slice(&self.claim.to_bytes());
196	        bytes.extend_from_slice(&self.recursive_proof.to_bytes());
197	        bytes
198	    }
199	}
