251	        let mut non_genesis_state: State = State {
252	            height: 100,
253	            ..Default::default()
254	        };
255	        // For height > 0, genesis_hash must be set
256	        non_genesis_state.genesis_hash = BlockHash::new([1; 32]);
257	        non_genesis_state.block_hash = BlockHash::new([2; 32]);
258	        non_genesis_state.header.prev_blockhash = BlockHash::new([3; 32]);
259	
260	        let expected_verifier_key = VerifierKeyDigest::from_raw([1; 8]);
261	        let expected_public_values_digest = PublicValuesDigest::from_raw([2; 32]);
262	        let recursive_proof_data = RecursiveProof {
263	            verifier_key: expected_verifier_key,
264	            public_values_digest: expected_public_values_digest,
265	            ..Default::default()
266	        };
