271	        assert_eq!(input.claim.height, 100);
272	        assert_eq!(input.recursive_proof.verifier_key, expected_verifier_key);
273	        assert_eq!(
274	            input.recursive_proof.public_values_digest,
275	            expected_public_values_digest
276	        );
277	    }
278	
279	    #[test]
280	    fn test_new_header_hints_round_trip() {
281	        let headers: Vec<NewHeader> = vec![
282	            NewHeader {
283	                version: 1,
284	                merkle_root: [4; 32],
285	                timestamp: BlockTimestamp::new(100),
286	                nonce: 0,
287	            },
288	            NewHeader {
289	                version: 2,
290	                merkle_root: [5; 32],
