304	        let headers = vec![NewHeader {
305	            version: 1,
306	            merkle_root: [4; 32],
307	            timestamp: BlockTimestamp::new(100),
308	            nonce: 0,
309	        }];
310	        let mut bytes = serialize_new_headers(&headers);
