323	    #[test]
324	    fn median_time_past_hints_round_trip() {
325	        let hints = vec![
326	            BlockTimestamp::new(0),
327	            BlockTimestamp::new(123),
328	            BlockTimestamp::new(456),
329	        ];
330	
331	        let bytes = serialize_median_hints(&hints);
332	        let parsed = parse_median_hints(&bytes, 3).unwrap();
333	
334	        assert_eq!(parsed, hints.as_slice());
335	    }
