337	    #[test]
338	    fn median_time_past_hints_reject_invalid_lengths() {
339	        let one_hint = serialize_median_hints(&[BlockTimestamp::new(123)]);
340	        let mut truncated_hint = one_hint.clone();
341	        truncated_hint.pop();
342	
343	        let cases = [
344	            (
345	                "wrong hint count",
346	                one_hint,
347	                2,
348	                MedianTimePastHintError::PayloadLengthInvalid {
349	                    expected: 8,
350	                    actual: 4,
351	                },
352	            ),
353	            (
354	                "truncated payload",
355	                truncated_hint,
356	                1,
357	                MedianTimePastHintError::PayloadLengthInvalid {
358	                    expected: 4,
359	                    actual: 3,
360	                },
361	            ),
362	        ];
363	
364	        for (name, bytes, expected_count, expected_error) in cases {
365	            let err = parse_median_hints(&bytes, expected_count).unwrap_err();
366	            assert_eq!(err, expected_error, "{name}");
367	        }
368	    }
369	}
