#[cfg(not(target_endian = "little"))]
compile_error!("zkpow wire types require a little-endian target");

use crate::{
    calculate_next_target_required, check_proof_of_work, copy_from_bytes, copy_to_bytes,
    work_from_target, ApplyFailure, BlockHash, BlockTimestamp, ChainWork,
    CompactTarget, Header, NewHeader, ParseError, PrivateContinuationState, PublicChainClaim,
    Target, TargetError, ValidationErrorCode, EPOCH_LENGTH, PRIVATE_CONTINUATION_STATE_SIZE,
    STATE_SIZE, WINDOW_SIZE,
};

#[cfg(all(target_os = "zkvm", feature = "profiling"))]
#[inline(always)]
pub fn cycle_track<T, F>(label: &'static str, f: F) -> T
where
    F: FnOnce() -> T,
{
    sp1_zkvm::io::write(
        1,
        alloc::format!("cycle-tracker-report-start: {label}\n").as_bytes(),
    );
    let output = f();
    sp1_zkvm::io::write(
        1,
        alloc::format!("cycle-tracker-report-end: {label}\n").as_bytes(),
    );
    output
}

#[cfg(not(all(target_os = "zkvm", feature = "profiling")))]
#[inline(always)]
pub fn cycle_track<T, F>(_label: &'static str, f: F) -> T
where
    F: FnOnce() -> T,
{
    f()
}

/// Complete authenticated validation state, serialized between recursive iterations.
#[repr(C)]
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct State {
    pub header: Header,
    pub block_hash: BlockHash,
    pub genesis_hash: BlockHash,
    pub current_nbits: CompactTarget,
    pub height: u32,
    pub chain_work: ChainWork,
    pub current_work: ChainWork,
    /// Expanded 256-bit target for the current difficulty period.
    /// Cached to avoid recomputing from `current_nbits` on every block.
    /// Updated only at retarget boundaries and at genesis.
    pub current_target: Target,
    pub epoch_start_timestamp: BlockTimestamp,
    pub timestamps: [BlockTimestamp; WINDOW_SIZE],
}

impl State {
    /// The number of timestamps currently tracked for median-time-past.
    #[must_use]
    pub fn timestamp_count(&self) -> usize {
        (self.height as usize + 1).min(WINDOW_SIZE)
    }

    /// The circular-buffer slot containing the current tip timestamp.
    #[must_use]
    fn current_timestamp_slot(&self) -> usize {
        self.height as usize % WINDOW_SIZE
    }

    /// Serialize to exactly [`STATE_SIZE`] bytes.
    #[must_use]
    pub fn to_bytes(&self) -> [u8; STATE_SIZE] {
        copy_to_bytes(self)
    }

    /// Deserialize from exactly [`STATE_SIZE`] bytes.
    pub fn parse(bytes: &[u8]) -> Result<Self, ParseError> {
        cycle_track("parse/state", || copy_from_bytes(bytes))
    }

    /// Extract the verifier-visible public claim from this state.
    #[must_use]
    pub fn public_claim(&self) -> PublicChainClaim {
        PublicChainClaim {
            genesis_hash: self.genesis_hash,
            tip_hash: self.block_hash,
            chain_work: self.chain_work,
            height: self.height,
        }
    }

    /// Serialize the private continuation fields directly to bytes.
    #[must_use]
    pub fn continuation_bytes(&self) -> [u8; PRIVATE_CONTINUATION_STATE_SIZE] {
        PrivateContinuationState::from_state(self).to_bytes()
    }

    /// Compute the difficulty values that become active at a new epoch boundary.
    fn prepare_new_epoch(
        &self,
        previous_timestamp: BlockTimestamp,
    ) -> Result<(CompactTarget, Target, ChainWork), TargetError> {
        cycle_track("state/prepare_new_epoch", || {
            let (current_nbits, current_target) = calculate_next_target_required(
                self.current_target,
                self.epoch_start_timestamp,
                previous_timestamp,
            );
            let current_work = work_from_target(current_target)?;
            Ok((current_nbits, current_target, current_work))
        })
    }

    #[must_use]
    fn median_time_past_hinted(&self, claimed_median: BlockTimestamp) -> bool {
        cycle_track("state/median_time_past_hinted", || {
            let window_len = self.timestamp_count();
            if window_len == 0 {
                return true;
            }

            let median_index = window_len / 2;

            let (less_count, equal_count, greater_count) =
                cycle_track("state/median_time_past_hinted/loop", || {
                    let mut less_count = 0usize;
                    let mut equal_count = 0usize;
                    let mut greater_count = 0usize;
                    for timestamp in self.timestamps.iter().take(window_len) {
                        if *timestamp < claimed_median {
                            less_count += 1;
                        } else if *timestamp > claimed_median {
                            greater_count += 1;
                        } else {
                            equal_count += 1;
                        }
                    }
                    (less_count, equal_count, greater_count)
                });

            cycle_track("state/median_time_past_hinted/check_counts", || {
                less_count + equal_count + greater_count == window_len
                    && less_count <= median_index
                    && less_count + equal_count > median_index
            })
        })
    }

    fn apply_chain_work_run(&mut self, run_work: ChainWork, run_count: u32) {
        if run_count > 0 {
            cycle_track("state/apply_headers/chain_work_flush", || {
                let accumulated_work = run_work * run_count;
                self.chain_work = self.chain_work + accumulated_work;
            });
        }
    }

    #[allow(clippy::result_large_err)]
    pub fn apply_headers<F>(
        &mut self,
        headers: &[NewHeader],
        median_hints: &[BlockTimestamp],
        mut hash_header: F,
    ) -> Result<(), ApplyFailure>
    where
        F: FnMut(&Header) -> BlockHash,
    {
        cycle_track("state/apply_headers", || {
            assert_eq!(
                headers.len(),
                median_hints.len(),
                "median hint count must match header count"
            );

            let mut pending_run_work: Option<ChainWork> = None;
            let mut pending_run_count: u32 = 0;

            let flush_pending_chain_work =
                |state: &mut State, run_work: &mut Option<ChainWork>, run_count: &mut u32| {
                    if let Some(run_work) = run_work.take() {
                        state.apply_chain_work_run(run_work, *run_count);
                    }
                    *run_count = 0;
                };

            for (header_index, (new_header, claimed_median)) in headers
                .iter()
                .copied()
                .zip(median_hints.iter().copied())
                .enumerate()
            {
                let candidate_height =
                    cycle_track("state/apply_headers/candidate_height", || self.height + 1);
                let previous_timestamp =
                    cycle_track("state/apply_headers/load_previous_timestamp", || {
                        self.timestamps[self.current_timestamp_slot()]
                    });
                let timestamp_slot = candidate_height as usize % WINDOW_SIZE;

                cycle_track("state/apply_headers/median_hint_check", || {
                    assert!(
                        self.median_time_past_hinted(claimed_median),
                        "invalid median time past hint at header index {}",
                        header_index
                    );
                });

                if cycle_track("state/apply_headers/validate/median_time_past", || {
                    new_header.timestamp <= claimed_median
                }) {
                    flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);
                    return Err(ApplyFailure {
                        last_valid_state: self.clone(),
                        error_code: ValidationErrorCode::TimestampTooOld,
                        failure_height: candidate_height,
                    });
                }

                let mut active_nbits = self.current_nbits;
                let mut active_target = self.current_target;
                let mut active_work = self.current_work;
                if cycle_track("state/apply_headers/check_retarget", || {
                    candidate_height.is_multiple_of(EPOCH_LENGTH)
                }) {
                    flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);
                    let prepared = self
                        .prepare_new_epoch(previous_timestamp)
                        .expect("epoch target must not be u256::MAX — invalid blockchain data");
                    active_nbits = prepared.0;
                    active_target = prepared.1;
                    active_work = prepared.2;
                }

                let header = cycle_track("state/apply_headers/build_header", || {
                    new_header.into_header(self.block_hash, active_nbits)
                });
                let block_hash =
                    cycle_track("state/apply_headers/hash_header", || hash_header(&header));

                if cycle_track("state/apply_headers/validate/pow", || {
                    !check_proof_of_work(block_hash, active_target)
                }) {
                    flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);
                    return Err(ApplyFailure {
                        last_valid_state: self.clone(),
                        error_code: ValidationErrorCode::PowInsufficient,
                        failure_height: candidate_height,
                    });
                }

                if pending_run_work != Some(active_work) {
                    flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);
                    pending_run_work = Some(active_work);
                }

                pending_run_count += 1;
                cycle_track("state/apply_headers/assign_state", || {
                    self.height = candidate_height;
                    self.timestamps[timestamp_slot] = header.timestamp;
                    self.current_nbits = active_nbits;
                    self.current_target = active_target;
                    self.current_work = active_work;
                    if candidate_height.is_multiple_of(EPOCH_LENGTH) {
                        self.epoch_start_timestamp = header.timestamp;
                    }
                    self.header = header;
                    self.block_hash = block_hash;
                });
            }

            flush_pending_chain_work(self, &mut pending_run_work, &mut pending_run_count);

            Ok(())
        })
    }
}

impl Default for State {
    fn default() -> Self {
        Self {
            header: Header::default(),
            block_hash: BlockHash::default(),
            genesis_hash: BlockHash::default(),
            current_nbits: CompactTarget::default(),
            height: 0,
            chain_work: ChainWork::default(),
            current_work: ChainWork::default(),
            current_target: Target::default(),
            epoch_start_timestamp: BlockTimestamp::default(),
            timestamps: [BlockTimestamp::default(); WINDOW_SIZE],
        }
    }
}

//! zkpow — Header-Construction Architecture
//!
//! Validates a batch of Bitcoin block headers incrementally.
//! The prover supplies only non-deterministic fields (version, merkle_root,
//! timestamp, nonce). The circuit constructs the full 80-byte header from
//! authenticated state, then hashes and validates.
//!
//! Input protocol:
//!   1. encoded_input: Vec<u8>  (PublicChainClaim || RecursiveProof)
//!   2. state_witness: Vec<u8>  (State bytes)
//!   3. header_hints: Vec<u8>
//!   4. median_time_past_hints: Vec<u8>
//!   5. If `claim.height > 0`, recursive proof witness (via write_proof)
//!
//! Output: MinimalPublicValues (169 bytes) on success or failure.

#![no_main]
sp1_zkvm::entrypoint!(main);

use zkpow_core::{
    cycle_track, parse_median_hints, parse_new_headers, BlockHash, Header, Input,
    MinimalPublicValues, PublicChainClaim, RecursiveProof, State, MINIMAL_PV_SIZE,
    PRIVATE_CONTINUATION_STATE_SIZE,
};

mod sha256;

use sha256::{sha256_116bytes, sha256_169bytes, sha256d_80bytes};

/// Hash a full 80-byte Bitcoin header with SHA256d.
fn hash_header(header: &Header) -> BlockHash {
    cycle_track("crypto/hash_header", || {
        let header_bytes = header.to_bytes();
        BlockHash::new(sha256d_80bytes(&header_bytes))
    })
}

/// Compute the continuation digest: SHA-256 of the serialized private continuation fields.
fn compute_continuation_digest(state: &State) -> [u8; 32] {
    cycle_track("crypto/continuation_digest", || {
        let pcs_bytes: [u8; PRIVATE_CONTINUATION_STATE_SIZE] = state.continuation_bytes();
        sha256_116bytes(&pcs_bytes)
    })
}

/// Commit the minimal public values and halt.
fn commit_minimal_pv(pv: &MinimalPublicValues) -> ! {
    let bytes: [u8; MINIMAL_PV_SIZE] = pv.to_bytes();
    sp1_zkvm::io::commit_slice(&bytes);
    sp1_zkvm::syscalls::syscall_halt(0)
}

// ============================================================================
// Recursive proof verification (Step 5 soundness model)
// ============================================================================

fn verify_recursive_proof(
    recursive_proof: &RecursiveProof,
    prior_claim: &PublicChainClaim,
    prior_continuation_bytes: &[u8; PRIVATE_CONTINUATION_STATE_SIZE],
) {
    cycle_track("recursive/verify_proof", || {
        // Reject continuation from a failed prior proof.
        if recursive_proof.previous_return_code != 0 {
            panic!(
                "recursive continuation rejected: prior proof has return code {}",
                recursive_proof.previous_return_code
            );
        }

        // 1. Hash the supplied continuation state.
        let continuation_digest = cycle_track("recursive/continuation_digest", || {
            sha256_116bytes(prior_continuation_bytes)
        });

        // 2. Reconstruct the prior proof's minimal public values and hash them.
        let prior_pv = MinimalPublicValues::success(
            prior_claim,
            continuation_digest,
            recursive_proof.verifier_key,
        );
        let prior_pv_bytes: [u8; MINIMAL_PV_SIZE] = prior_pv.to_bytes();
        let actual_pv_hash = cycle_track("recursive/public_values_digest", || {
            sha256_169bytes(&prior_pv_bytes)
        });

        if actual_pv_hash != recursive_proof.public_values_digest.into_raw() {
            panic!("recursive proof public values digest mismatch");
        }

        // 3. Verify the SP1 proof.
        cycle_track("recursive/sp1_verify", || {
            sp1_zkvm::lib::verify::verify_sp1_proof(
                recursive_proof.verifier_key.as_raw(),
                recursive_proof.public_values_digest.as_raw(),
            );
        });
    });
}

pub fn main() {
    cycle_track("main", || {
        let input_bytes = sp1_zkvm::io::read_vec();
        let state_bytes = sp1_zkvm::io::read_vec();
        let header_hint_bytes = sp1_zkvm::io::read_vec();
        let median_hint_bytes = sp1_zkvm::io::read_vec();

        let input = Input::parse(&input_bytes).expect("input should parse");
        let mut state = cycle_track("input/parse_state_witness", || {
            State::parse(&state_bytes).expect("state witness should parse")
        });
        cycle_track("input/verify_state_claim", || {
            assert!(
                state.genesis_hash == input.claim.genesis_hash
                    && state.block_hash == input.claim.tip_hash
                    && state.chain_work == input.claim.chain_work
                    && state.height == input.claim.height,
                "state witness public claim mismatch"
            );
        });
        let header_hints = cycle_track("input/parse_header_hints", || {
            parse_new_headers(&header_hint_bytes).expect("new header hints should parse")
        });
        let median_hints = cycle_track("input/parse_median_hints", || {
            parse_median_hints(&median_hint_bytes, header_hints.len())
                .expect("median time past hints should parse")
        });

        if input.claim.height > 0 {
            let prior_continuation_bytes: [u8; PRIVATE_CONTINUATION_STATE_SIZE] =
                state.continuation_bytes();
            verify_recursive_proof(
                &input.recursive_proof,
                &input.claim,
                &prior_continuation_bytes,
            );
        }

        // Apply headers; on failure commit minimal PV and halt.
        if let Err(failure) = state.apply_headers(header_hints, median_hints, hash_header) {
            let digest = compute_continuation_digest(&failure.last_valid_state);
            let pv = MinimalPublicValues::failure(
                &failure.last_valid_state.public_claim(),
                failure.error_code,
                failure.failure_height,
                digest,
                input.recursive_proof.verifier_key,
            );
            commit_minimal_pv(&pv);
        }

        let digest = compute_continuation_digest(&state);
        let pv = MinimalPublicValues::success(
            &state.public_claim(),
            digest,
            input.recursive_proof.verifier_key,
        );
        commit_minimal_pv(&pv);
    });
}
